import{_ as t,o,c as d,ag as c}from"./chunks/framework.CxQaEjLZ.js";const u=JSON.parse('{"title":"How It Works","description":"","frontmatter":{},"headers":[],"relativePath":"how-it-works.md","filePath":"how-it-works.md"}'),a={name:"how-it-works.md"};function r(s,e,i,n,l,p){return o(),d("div",null,[...e[0]||(e[0]=[c('<h1 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h1><p>depdet runs two passes over a TypeScript Program built via <a href="https://ts-morph.com" target="_blank" rel="noreferrer">ts-morph</a>.</p><h2 id="pass-1-collect-deprecated-declarations" tabindex="-1">Pass 1: Collect deprecated declarations <a class="header-anchor" href="#pass-1-collect-deprecated-declarations" aria-label="Permalink to &quot;Pass 1: Collect deprecated declarations&quot;">​</a></h2><p>Walks every declaration in scope — <code>function</code>, <code>method</code>, <code>class</code>, <code>property</code>, <code>variable</code>, <code>type</code>, <code>interface</code>, <code>enum</code>, and accessor — and checks for a <code>@deprecated</code> JSDoc tag.</p><p>This includes:</p><ul><li>Your own source files</li><li>Type definitions in <code>node_modules</code> (<code>.d.ts</code> files) — unless <code>--no-deps</code> is set</li></ul><h2 id="pass-2-match-identifiers-in-your-source" tabindex="-1">Pass 2: Match identifiers in your source <a class="header-anchor" href="#pass-2-match-identifiers-in-your-source" aria-label="Permalink to &quot;Pass 2: Match identifiers in your source&quot;">​</a></h2><p>Every identifier in your source files is checked against the TypeScript type checker to see if it resolves to a deprecated declaration.</p><p>The checker follows:</p><ul><li>Re-exports (<code>export { foo } from &#39;./bar&#39;</code>)</li><li>Method chains (<code>z.string().email()</code> resolves through each call)</li><li>Property access (<code>obj.deprecatedProp</code>)</li></ul><h2 id="replacement-extraction" tabindex="-1">Replacement extraction <a class="header-anchor" href="#replacement-extraction" aria-label="Permalink to &quot;Replacement extraction&quot;">​</a></h2><p>For each deprecated declaration, depdet tries to extract the replacement hint in this order:</p><table tabindex="0"><thead><tr><th>Strategy</th><th>Example JSDoc</th></tr></thead><tbody><tr><td><code>{@link X}</code></td><td><code>@deprecated Use {@link newFn} instead</code></td></tr><tr><td><code>{@linkcode X}</code></td><td><code>@deprecated {@linkcode newFn}</code></td></tr><tr><td><code>{@linkplain X}</code></td><td><code>@deprecated {@linkplain newFn}</code></td></tr><tr><td>Free-text: use</td><td><code>@deprecated Use newFn instead</code></td></tr><tr><td>Free-text: replaced by</td><td><code>@deprecated Replaced by newFn</code></td></tr><tr><td>Free-text: prefer</td><td><code>@deprecated Prefer newFn</code></td></tr><tr><td>Bareword variants</td><td><code>@deprecated newFn</code></td></tr></tbody></table><p>If no hint is found, <code>replacement</code> is <code>null</code>.</p><h2 id="non-goals" tabindex="-1">Non-goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-goals&quot;">​</a></h2><ul><li><strong>Auto-fix</strong> - writing replacements back to files (planned for <code>--fix</code>)</li><li><strong><code>.vue</code> / <code>.svelte</code> / <code>.astro</code></strong> - only <code>.ts</code>, <code>.tsx</code>, <code>.js</code>, <code>.jsx</code>, <code>.d.ts</code></li><li><strong>Runtime detection</strong> - only static analysis via JSDoc, not runtime <code>console.warn</code> deprecations</li></ul>',16)])])}const f=t(a,[["render",r]]);export{u as __pageData,f as default};
